import React, { useEffect, useRef, useState } from 'react'
import { API } from '../../api'              // ← убедись, что метод возврата добавлен
import { useNavigate } from 'react-router-dom'

const th = { border: '1px solid #ccc', padding: 10, textAlign: 'left' }
const td = { border: '1px solid #eee', padding: 10 }
const btn = { width: 28, height: 28, margin: '0 4px', border: '1px solid #ccc', background: '#fff', cursor: 'pointer' }

const Return = () => {
  const [goods, setGoods]        = useState([])  // все товары со склада
  const [cart,  setCart]         = useState([])  // что возвращаем
  const [reason, setReason]      = useState('defect')
  const inputRef                 = useRef()
  const navigate                 = useNavigate()

  /* общая сумма возврата */
  const total = cart.reduce((s, i) => s + i.qty * +i.price, 0)

  /* --- грузим текущий склад --- */
  useEffect(() => {
    API.getStocks()
      .then(r => setGoods(r.data))
      .catch(e => console.error('Ошибка загрузки товаров', e))
  }, [])

  /* --- сканирование --- */
  const handleScan = e => {
    if (e.key !== 'Enter') return
    const code = e.target.value.trim()
    if (!code) return

    const item = goods.find(g => g.code === code)
    if (!item) { alert('Товар не найден'); e.target.value = ''; return }

    setCart(prev => {
      const ex = prev.find(p => p.id === item.id)
      return ex
        ? prev.map(p => p.id === item.id ? { ...p, qty: Math.min(p.qty + 1, p.quantity) } : p)
        : [...prev, { ...item, qty: 1 }]
    })
    e.target.value = ''
  }

  /* --- изменить количество --- */
  const changeQty = (idx, delta) =>
    setCart(prev =>
      prev.map((r, i) => i === idx
        ? { ...r, qty: Math.max(1, Math.min(r.qty + delta, r.quantity)) }
        : r))

  const setQtyManually = (idx, val) =>
    setCart(prev =>
      prev.map((r, i) => i === idx
        ? { ...r, qty: Math.max(1, Math.min(parseInt(val) || 1, r.quantity)) }
        : r))

  const removeItem = idx => setCart(prev => prev.filter((_, i) => i !== idx))

  /* --- отправка возврата --- */
  const handleReturn = async () => {
    if (!cart.length) return alert('Позиции для возврата не выбраны')

    try {
      const payload = cart.map(i => ({
        sale_item: i.id,
        quantity: i.qty
      }))

      await API.createReturn(payload)
      alert('Возврат оформлен')
      setCart([])
      navigate('/returns-report')       // если нужен отчёт
    } catch (e) {
      console.error('Ошибка возврата', e)
      alert('Ошибка при возврате')
    }
  }

  return (
    <div style={{ padding: 24, maxWidth: 900, margin: '0 auto', fontFamily: 'sans-serif' }}>
      <h2>🔄 Возврат товара</h2>

      <input
        ref={inputRef}
        placeholder="Сканируйте штрихкод…"
        onKeyDown={handleScan}
        autoFocus
        style={{ width: '100%', padding: 12, fontSize: 16, marginBottom: 20 }}
      />

      <div style={{ marginBottom: 20 }}>
        <label>Причина возврата:&nbsp;</label>
        <select value={reason} onChange={e => setReason(e.target.value)}>
          <option value="defect">Дефект</option>
          <option value="customer">Покупатель вернул</option>
          <option value="expiry">Истёк срок годности</option>
        </select>
      </div>

      <table style={{ width: '100%', borderCollapse: 'collapse', marginBottom: 20 }}>
        <thead style={{ background: '#f0f0f0' }}>
          <tr>
            <th style={th}>Название</th>
            <th style={th}>Цена</th>
            <th style={th}>Кол-во</th>
            <th style={th}>Сумма</th>
            <th style={th}></th>
          </tr>
        </thead>
        <tbody>
          {cart.map((it, idx) => (
            <tr key={idx}>
              <td style={td}>{it.name}</td>
              <td style={td}>{(+it.price).toFixed(2)} сом</td>
              <td style={td}>
                <button onClick={() => changeQty(idx, -1)} style={btn}>−</button>
                <input
                  type="number" min={1}
                  value={it.qty}
                  onChange={e => setQtyManually(idx, e.target.value)}
                  style={{ width: 50, textAlign: 'center' }}
                />
                <button onClick={() => changeQty(idx, +1)} style={btn}>+</button>
                <div style={{ fontSize: 11, color: '#888' }}>
                  Доступно: {it.quantity}
                </div>
              </td>
              <td style={td}>{(it.qty * +it.price).toFixed(2)} сом</td>
              <td style={td}>
                <button onClick={() => removeItem(idx)} style={{...btn, background:'#ff4d4f', color:'#fff'}}>×</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>

      <h3 style={{ textAlign: 'right' }}>К возврату: {total.toFixed(2)} сом</h3>

      <div style={{ textAlign: 'right', marginTop: 20 }}>
        <button onClick={handleReturn} style={{ background:'#f39c12', color:'#fff', padding:'10px 20px', border:'none', cursor:'pointer' }}>
          🛒 Оформить возврат
        </button>
      </div>
    </div>
  )
}

export default Return
